    public static CatalogResult<SqlCatalogEntry> Find(string fileName) => s_entries.FirstOrDefault(x => string.Equals(x.FileName,fileName,StringComparison.OrdinalIgnoreCase)) is { } entry ? CatalogResult<SqlCatalogEntry>.Success(entry) : CatalogResult<SqlCatalogEntry>.Failure([new(SqlCatalogFailureCode.UnexpectedSqlFile,fileName)]);
    public static CatalogResult<VerifiedNewInstallPackage> ValidateNewInstallFiles(IReadOnlyList<SqlFileInput> files) => Validate(files, s_entries.Where(x=>x.IncludeInNewInstall).OrderBy(x=>x.StableOrder).ToArray(), null, null);
    public static CatalogResult<VerifiedUpgradePackage> ValidateUpgradeFiles(string currentVersion, string? targetVersion, IReadOnlyList<SqlFileInput> files)
    {
        if (!SqlVersion.TryParse(currentVersion,out var current)) return CatalogResult<VerifiedUpgradePackage>.Failure([new(SqlCatalogFailureCode.InvalidVersion, Message:"Current version is invalid.")]);
        SqlVersion? requested = null;
        if (targetVersion is not null)
        {
            if (!SqlVersion.TryParse(targetVersion, out var parsedTarget)) return CatalogResult<VerifiedUpgradePackage>.Failure([new(SqlCatalogFailureCode.InvalidVersion, Message:"Target version is invalid.")]);
            requested = parsedTarget;
        }
        var path = Plan(current,requested); if (!path.Succeeded) return CatalogResult<VerifiedUpgradePackage>.Failure(path.Failures);
        var required = s_entries.Where(x=>x.IncludeInKeyFilePayload).Concat(path.Value!).Distinct().OrderBy(x=>x.StableOrder).ToArray();
        var baseResult=Validate(files,required,current,path.Value!); if(!baseResult.Succeeded) return CatalogResult<VerifiedUpgradePackage>.Failure(baseResult.Failures);
        var all=baseResult.Value!.FilesByName.Values; var upgrades=path.Value!.Select(x=>all.Single(y=>y.CatalogEntry==x)); var payload=all.Where(x=>x.CatalogEntry.IncludeInKeyFilePayload).OrderBy(x=>x.CatalogEntry.StableOrder);
        return CatalogResult<VerifiedUpgradePackage>.Success(new VerifiedUpgradePackage(current,path.Value!.LastOrDefault()?.UpgradeToVersion ?? current,upgrades,payload,all));
    }
    public static CatalogResult<VerifiedNewInstallPackage> LoadAndValidateNewInstallDirectory(string path) => Load(path, ValidateNewInstallFiles);
    public static CatalogResult<VerifiedUpgradePackage> LoadAndValidateUpgradeDirectory(string path,string current,string? target) => Load(path, f=>ValidateUpgradeFiles(current,target,f));
    private static CatalogResult<T> Load<T>(string path, Func<IReadOnlyList<SqlFileInput>,CatalogResult<T>> validator) { try { if(!Directory.Exists(path)) return CatalogResult<T>.Failure([new(SqlCatalogFailureCode.IoFailure, Message:"SQL directory does not exist.")]); var files=Directory.EnumerateFiles(path,"*",SearchOption.TopDirectoryOnly).Where(x=>string.Equals(Path.GetExtension(x),".sql",StringComparison.OrdinalIgnoreCase)).Select(x=>new SqlFileInput(Path.GetFileName(x),File.ReadAllBytes(x),x)).ToArray(); return validator(files); } catch(Exception ex) { return CatalogResult<T>.Failure([new(SqlCatalogFailureCode.IoFailure, Message:ex.Message)]); } }
    private static CatalogResult<VerifiedNewInstallPackage> Validate(IReadOnlyList<SqlFileInput> files, SqlCatalogEntry[] required, SqlVersion? current, IReadOnlyList<SqlCatalogEntry>? path)
    {
        var failures=ValidateDefinition().ToList(); var sql=files.Where(x=>Path.GetExtension(x.FileName).Equals(".sql",StringComparison.OrdinalIgnoreCase)).ToArray();
        foreach(var group in sql.GroupBy(x=>x.FileName,StringComparer.OrdinalIgnoreCase).Where(g=>g.Count()>1)) failures.Add(new(SqlCatalogFailureCode.DuplicateFileName,group.Key));
        var known=s_entries.ToDictionary(x=>x.FileName,StringComparer.OrdinalIgnoreCase); foreach(var file in sql) if(!known.ContainsKey(file.FileName)) failures.Add(new(SqlCatalogFailureCode.UnexpectedSqlFile,file.FileName,SourceDescription:file.SourceDescription));
        if (failures.Count > 0) return CatalogResult<VerifiedNewInstallPackage>.Failure(failures);
        foreach(var entry in required) { var file=sql.SingleOrDefault(x=>string.Equals(x.FileName,entry.FileName,StringComparison.OrdinalIgnoreCase)); if(file is null) failures.Add(new(SqlCatalogFailureCode.MissingRequiredFile,entry.FileName)); else if(file.RawBytes.Length==0) failures.Add(new(SqlCatalogFailureCode.EmptyFile,entry.FileName,SourceDescription:file.SourceDescription)); else { var actual=Convert.ToHexString(SHA256.HashData(file.RawBytes.Span)).ToLowerInvariant(); if(actual!=entry.Sha256Hex) failures.Add(new(SqlCatalogFailureCode.HashMismatch,entry.FileName,entry.Sha256Hex,actual,SourceDescription:file.SourceDescription)); } }
        if(failures.Count>0) return CatalogResult<VerifiedNewInstallPackage>.Failure(failures);
        var verified=new List<VerifiedSqlFile>(); try { foreach(var entry in required.OrderBy(x=>x.StableOrder)) { var file=sql.Single(x=>string.Equals(x.FileName,entry.FileName,StringComparison.OrdinalIgnoreCase)); verified.Add(new(entry,file.RawBytes.ToArray(),new UTF8Encoding(false,true).GetString(file.RawBytes.Span))); } } catch(DecoderFallbackException ex) { return CatalogResult<VerifiedNewInstallPackage>.Failure([new(SqlCatalogFailureCode.DecodeFailure, Message:ex.Message)]); }
        var creation=verified.Single(x=>x.CatalogEntry.Role.HasFlag(SqlScriptRole.DatabaseCreation)); return CatalogResult<VerifiedNewInstallPackage>.Success(new VerifiedNewInstallPackage(creation,verified.Where(x=>x.CatalogEntry.IncludeInKeyFilePayload),verified));
    }
    private static CatalogResult<IReadOnlyList<SqlCatalogEntry>> Plan(SqlVersion current, SqlVersion? requested)
    { var edges=s_entries.Where(x=>x.Role.HasFlag(SqlScriptRole.Upgrade)).ToArray(); if(!edges.Any(x=>x.UpgradeFromVersion!.Value.CompareTo(current)==0) && current.CompareTo(SqlVersion.Parse("1.23")) != 0) return CatalogResult<IReadOnlyList<SqlCatalogEntry>>.Failure([new(SqlCatalogFailureCode.UnsupportedVersionTransition, Message:"Current version is not supported.")]); var target=requested; if(target is { } t && t.CompareTo(current)<0) return CatalogResult<IReadOnlyList<SqlCatalogEntry>>.Failure([new(SqlCatalogFailureCode.UnsupportedVersionTransition, Message:"Downgrade is not supported.")]); var route=new List<SqlCatalogEntry>(); var at=current; while(true) { var next=edges.Where(x=>x.UpgradeFromVersion!.Value.CompareTo(at)==0).OrderBy(x=>x.UpgradeToVersion).ToArray(); if(next.Length>1)return CatalogResult<IReadOnlyList<SqlCatalogEntry>>.Failure([new(SqlCatalogFailureCode.AmbiguousUpgradePath)]); if(next.Length==0)break; if(target is { } desired && next[0].UpgradeToVersion!.Value.CompareTo(desired)>0) break; route.Add(next[0]); at=next[0].UpgradeToVersion!.Value; if(target is { } wanted && at.CompareTo(wanted)==0)break; }
      if(target is { } targetValue && at.CompareTo(targetValue)!=0)return CatalogResult<IReadOnlyList<SqlCatalogEntry>>.Failure([new(SqlCatalogFailureCode.NoValidUpgradePath)]); return CatalogResult<IReadOnlyList<SqlCatalogEntry>>.Success(Array.AsReadOnly(route.ToArray())); }
    private static IEnumerable<SqlCatalogFailure> ValidateDefinition() { if(s_entries.Count(x=>x.Role.HasFlag(SqlScriptRole.DatabaseCreation))!=1) yield return new(SqlCatalogFailureCode.InvalidCatalogDefinition, Message:"Expected one creation entry."); foreach(var e in s_entries) { if(Path.GetFileName(e.FileName)!=e.FileName || string.IsNullOrWhiteSpace(e.FileName) || !System.Text.RegularExpressions.Regex.IsMatch(e.Sha256Hex,"^[0-9a-f]{64}$")) yield return new(SqlCatalogFailureCode.InvalidCatalogDefinition,e.FileName); if(e.Role.HasFlag(SqlScriptRole.DatabaseCreation) && (!e.IncludeInNewInstall || !e.IncludeInKeyFilePayload)) yield return new(SqlCatalogFailureCode.InvalidCatalogDefinition,e.FileName,Message:"Creation SQL must be in both packages."); if(e.Role.HasFlag(SqlScriptRole.Upgrade) ? e.UpgradeFromVersion is null || e.UpgradeToVersion is null || e.UpgradeFromVersion.Value.CompareTo(e.UpgradeToVersion.Value)>=0 : e.UpgradeFromVersion is not null || e.UpgradeToVersion is not null) yield return new(SqlCatalogFailureCode.InvalidCatalogDefinition,e.FileName); } if(s_entries.GroupBy(x=>x.FileName,StringComparer.OrdinalIgnoreCase).Any(g=>g.Count()>1) || s_entries.GroupBy(x=>x.StableOrder).Any(g=>g.Count()>1) || s_entries.Where(x=>x.Role.HasFlag(SqlScriptRole.Upgrade)).GroupBy(x=>(x.UpgradeFromVersion!.Value.ToString(),x.UpgradeToVersion!.Value.ToString())).Any(g=>g.Count()>1)) yield return new(SqlCatalogFailureCode.InvalidCatalogDefinition, Message:"Duplicate catalog filename, order, or transition."); }
    private static SqlCatalogEntry C(string n,string h,int o)=>new(n,h,SqlScriptRole.DatabaseCreation,true,true,null,null,o); private static SqlCatalogEntry N(string n,string h,int o)=>new(n,h,SqlScriptRole.NormalOperational,true,true,null,null,o); private static SqlCatalogEntry U(string n,string h,string f,string t,int o)=>new(n,h,SqlScriptRole.Upgrade,false,false,SqlVersion.Parse(f),SqlVersion.Parse(t),o);
